export const EventType = {
	INPUT: 'input',
	THOUGHT: 'thought',
	ACTION: 'action',
	OBSERVATION: 'observation',
	OUTPUT: 'output',

	// 方便 UI 订阅
	AGENT_START: 'agent_start',
	THOUGHT_START: 'thought_start',
	THOUGHT_DONE: 'thought_done',
	AGENT_DONE: 'agent_done',
	AGENT_ERROR: 'agent_error',
} as const;

export type InputEvent = {
	type: typeof EventType.INPUT;
	text: string;
	source?: 'user' | 'system';
};

export type ThoughtEvent = {
	type: typeof EventType.THOUGHT;
	text: string;
};

export type ActionEvent = {
	type: typeof EventType.ACTION;
	id: string;
	name: string;
	args: Record<string, any>;
};

export type ObservationEvent = {
	type: typeof EventType.OBSERVATION;
	id: string;
	name: string;
	result: any;
};

export type OutputEvent = {
	type: typeof EventType.OUTPUT;
	text: string;
};

export type AgentStartEvent = { type: typeof EventType.AGENT_START };
export type AgentThoughtStartEvent = { type: typeof EventType.THOUGHT_START };
export type AgentThoughtDoneEvent = { type: typeof EventType.THOUGHT_DONE };
export type AgentDoneEvent = { type: typeof EventType.AGENT_DONE };
export type AgentError = { type: typeof EventType.AGENT_ERROR; message: string };

export type AgentEvent =
	| InputEvent
	| ThoughtEvent
	| ActionEvent
	| ObservationEvent
	| OutputEvent
	// 下面是方便 UI 订阅的
	| AgentStartEvent
	| AgentThoughtStartEvent
	| AgentThoughtDoneEvent
	| AgentDoneEvent
	| AgentError;

import { listFilesTool, readFileTool } from './builtins';

import type { ToolDefinition } from './types';

class ToolRegistry {
	private tools = new Map<string, ToolDefinition<any, any>>();

	register(tool: ToolDefinition<any, any>): void {
		this.tools.set(tool.name, tool);
	}

	get(name: string): ToolDefinition<any, any> | undefined {
		return this.tools.get(name);
	}

	list(): Omit<ToolDefinition<any, any>, 'execute'>[] {
		return Array.from(this.tools.values()).map((tool) => ({
			name: tool.name,
			description: tool.description,
			schema: tool.schema,
		}));
	}
}

const toolRegistry = new ToolRegistry();

toolRegistry.register(readFileTool);
toolRegistry.register(listFilesTool);

export default toolRegistry;

export type ToolMeta = {
	name: string;
	description: string;
	schema: {
		type: 'object';
		properties: Record<
			string,
			{
				type: unknown;
				description: string;
			}
		>;
		required?: string[];
		additionalProperties?: boolean;
	};
};

export type ToolContext = {
	cwd: string;
};

export interface ToolDefinition<T, U> extends ToolMeta {
	execute(p: T, context: ToolContext): U;
}

import fs from 'fs/promises';
import path from 'path';
import type { ToolDefinition } from './types';

export const readFileTool: ToolDefinition<{ path: string }, Promise<string>> = {
	name: 'read_file',
	description: 'Read the full contents of a specific file when the user asks to inspect, open, or read a file.',
	schema: {
		type: 'object',
		properties: {
			path: {
				type: 'string',
				description: 'The user-specified file path to read, resolved relative to the agent working directory.',
			},
		},
		required: ['path'],
		additionalProperties: false,
	},

	async execute(p, context) {
		const realPath = path.resolve(context.cwd, p.path);
		try {
			return await fs.readFile(realPath, { encoding: 'utf8' });
		} catch (e) {
			return e instanceof Error ? e.message : String(e);
		}
	},
};

export const listFilesTool: ToolDefinition<
	{ path?: string },
	Promise<{
		path: string;
		entries: {
			name: string;
			type: 'file' | 'directory';
		}[];
		errorMessage?: string;
	}>
> = {
	name: 'list_files',
	description: 'List files and directories directly under a directory.',
	schema: {
		type: 'object',
		properties: {
			path: {
				type: 'string',
				description: 'Directory path relative to the agent working directory. Defaults to current directory.',
			},
		},
	},
	async execute(p, context) {
		const targetPath = p.path ?? '.';
		const realPath = path.resolve(context.cwd, targetPath);

		try {
			const entries = await fs.readdir(realPath, { withFileTypes: true });
			return {
				path: targetPath,
				entries: entries.map((entry) => ({
					name: entry.name,
					type: entry.isFile() ? 'file' : 'directory',
				})),
			};
		} catch (e) {
			return {
				path: targetPath,
				entries: [],
				errorMessage: e instanceof Error ? e.message : String(e),
			};
		}
	},
};

